import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom"; // 1. استيراد التنقل
import "./Cake.css";

const commonStyles = {
  container: "layout_container",
  headerWrapper: "Header_wrapper",
  headerSubtitle: "Header_subtitle",
  headerTitle: "Header_title",
};

const SectionHeader = ({ title, subtitle }) => (
  <div className={commonStyles.headerWrapper}>
    <span className={commonStyles.headerSubtitle}>{subtitle}</span>
    <h2 className={commonStyles.headerTitle}>{title}</h2>
  </div>
);

const Cake = () => {
  // تم تغيير الاسم لـ Cake
  const [activeFilter, setActiveFilter] = useState("marshmallow");
  const navigate = useNavigate(); // 2. تعريف هوك التنقل

  const filters = [{ id: "marshmallow", label: "كيك مع المارشميلو" }];

  const products = [
    {
      id: 101, // يفضل استخدام أرقام مميزة عن البسكويت
      name: "Hugy Moosh Milk",
      category: "marshmallow",
      desc: "كيك الحليب المغطس بالشوكولا والمحشي بالمارشميلو",
      img: "/images/Product3/HugyMooshWhiteEaten.webp",
      // أضفنا مصفوفة الصور والمكونات لصفحة التفاصيل
      images: [
        "/images/Product3/HugyMooshWhiteEaten.webp",
        "/images/Product3/HugyMooshWhite.webp",
      ],
      ingredients: [
        "سكر",
        "زيوت نباتية مهدرجة بالكامل",
        "دقيق القمح",
        "جلكوز",
        "حليب خالي من الدسم",
        "سوربيتول",
        "بكتين",
        "ليستين الصويا E322",
        "بيكربونات الصوديوم",
        "ملح الطعام",
        "فانيليا",
        "جيلاتين بقري",
      ],
    },
    {
      id: 102,
      name: "Hugy Moosh Chocolate",
      category: "marshmallow",
      desc: "كيك الشوكولا المغطس بالشوكولا والمحشي بالمارشميلو",
      img: "/images/Product2/HugyMooshDarkEaten.webp",
      images: [
        "/images/Product2/HugyMooshDarkEaten.webp",
        "/images/Product2/HugyMooshDark.webp",
      ],
      ingredients: [
        "سكر",
        "زيوت نباتية مهدرجة",
        "دقيق القمح",
        "جلوكوز",
        "بودرة الكاكاو",
        "كتلة الكاكاو",
        "حليب خالي الدسم",
        "ليستين الصويا E322",
        "ملح الطعام",
        "جيلاتين بقري",
      ],
    },
  ];

  const filteredProducts = products.filter((p) => p.category === activeFilter);

  useEffect(() => {
    const observerOptions = { threshold: 0.1 };
    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add("is-visible");
        } else {
          entry.target.classList.remove("is-visible");
        }
      });
    }, observerOptions);

    const cards = document.querySelectorAll(".Catalog_card");
    cards.forEach((card) => observer.observe(card));

    return () => observer.disconnect();
  }, [filteredProducts]);

  return (
    <div className="cake-container">
      {" "}
      {/* تغيير الكلاس لـ cake */}
      <div className={commonStyles.container}>
        <SectionHeader title="تصفح منتجات الكيك" subtitle="طعم لا يُنسى" />

        <div className="Catalog_filterWrapper">
          {filters.map((filter) => (
            <button
              key={filter.id}
              className={`Catalog_filterBtn ${
                activeFilter === filter.id ? "Catalog_filterBtnActive" : ""
              }`}
              onClick={() => setActiveFilter(filter.id)}
            >
              {filter.label}
            </button>
          ))}
        </div>

        <div className="Catalog_grid">
          {filteredProducts.map((product) => (
            <div
              key={product.id}
              className="Catalog_card"
              onClick={() =>
                navigate(`/product/${product.id}`, { state: { product } })
              } // 3. إضافة النقر
              style={{ cursor: "pointer" }} // لجعل الماوس يشير للنقر
            >
              <div className="Catalog_imgContainer">
                <img
                  src={product.img}
                  alt={product.name}
                  className="Catalog_img"
                />
              </div>
              <div className="Catalog_info">
                <h4 className="Catalog_name">{product.name}</h4>
                <div className="Catalog_desc">
                  <p>{product.desc}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Cake;
